import { createEffect, mergeProps, on, onCleanup, ParentComponent, Show } from 'solid-js';
import { Portal } from 'solid-js/web';
import { cn } from '@/utils/cn';
import { acquire, acquireScrollLock, release, releaseScrollLock } from './z-index.store';
import { useParentZIndex, ZIndexContext } from './z-index.context';
import { ZIndexType, type ZIndexProps } from './z-index.types';

export { ZIndexType } from './z-index.types';
export type { ZIndexProps } from './z-index.types';
export { acquire, release } from './z-index.store';

/** Base z-index for each type group when no parent context exists. */
export const OFFSET: Record<ZIndexType, number> = {
  [ZIndexType.DROPDOWN]: 200,
  [ZIndexType.POPOVER]: 200,
  [ZIndexType.OVERLAY]: 500,
  [ZIndexType.MODAL]: 1000,
  [ZIndexType.TOOLTIP]: 1500,
  [ZIndexType.TOAST]: 3000,
};

/**
 * Relative offset added to the parent container's z-index when a child popup
 * renders inside a container (MODAL or OVERLAY). This ensures correct stacking:
 * e.g., a dropdown inside a modal gets parentZIndex + 50, always above the modal.
 */
const RELATIVE_OFFSET: Partial<Record<ZIndexType, number>> = {
  [ZIndexType.DROPDOWN]: 10,
  [ZIndexType.POPOVER]: 20,
  [ZIndexType.TOOLTIP]: 30,
};

/**
 * Container types that publish their z-index via ZIndexContext so that
 * child popup components can calculate their z-index relative to this parent.
 */
const CONTAINER_TYPES = new Set<ZIndexType>([ZIndexType.MODAL, ZIndexType.OVERLAY]);

/**
 * Compute the effective base index for slot allocation.
 *
 * - If a parent container z-index exists AND this type has a relative offset:
 *   use `parentZIndex + relativeOffset` (context-aware mode).
 * - Otherwise: use the global `baseIndex` from OFFSET (top-level mode).
 */
function computeEffectiveBase(
  type: string,
  globalBase: number,
  parentZIndex: number | undefined,
): number {
  if (parentZIndex === undefined) return globalBase;
  const relativeOffset = RELATIVE_OFFSET[type as ZIndexType];
  if (relativeOffset === undefined) return globalBase;
  return parentZIndex + relativeOffset;
}

/**
 * ZIndex — wrapper component that renders children via Portal with an
 * auto-managed z-index from a centralized global registry.
 *
 * When `open` becomes true, it acquires the next available z-index slot
 * for the given type group. When `open` becomes false (or the component
 * unmounts), the slot is released back to the pool.
 *
 * Container types (MODAL, OVERLAY) additionally publish their z-index via
 * ZIndexContext, allowing nested popup children to auto-offset correctly.
 */
export const ZIndex: ParentComponent<ZIndexProps> = props => {
  const p = mergeProps({ positioning: 'fixed' as const }, props);

  const baseIndex = (): number => {
    if (p.startIndex !== undefined) return p.startIndex;
    return OFFSET[p.type as ZIndexType] ?? 0;
  };

  /**
   * Inner component — only rendered when `open` is true (or always when preRender).
   * This ties acquire/release to the actual Portal mount/unmount lifecycle.
   */
  const Inner: ParentComponent = innerProps => {
    let zIndex: number;

    if (p.customValue !== undefined) {
      zIndex = p.customValue;
      p.onZIndex?.(zIndex);
      if (p.blockScroll) acquireScrollLock();
      onCleanup(function releaseScrollLockOnUnmount() {
        if (p.blockScroll) releaseScrollLock();
      });
    } else {
      const parentZIndex = useParentZIndex();
      const effectiveBase = computeEffectiveBase(p.type, baseIndex(), parentZIndex);
      const acquired = acquire(p.type, effectiveBase);
      zIndex = acquired.zIndex;
      p.onZIndex?.(zIndex);
      if (p.blockScroll) acquireScrollLock();
      onCleanup(function releaseZIndexAndScrollLock() {
        release(acquired.registryKey, acquired.offset);
        if (p.blockScroll) releaseScrollLock();
      });
    }

    const isContainer = CONTAINER_TYPES.has(p.type as ZIndexType);

    // Container types (MODAL, OVERLAY) publish their z-index via ZIndexContext
    // so that nested popups (Dropdown, Tooltip…) can auto-offset correctly.
    // The Provider MUST live INSIDE the Portal so SolidJS's reactive ownership
    // tree propagates the context into the Portal's scope. Wrapping the Portal
    // element from the outside does NOT work because Portal creates its own
    // reactive scope when mounting into document.body.
    return (
      <Portal>
        <div
          class={cn(p.positioning === 'fixed' ? 'fixed' : 'absolute', p.class)}
          style={{ 'z-index': zIndex, ...p.position }}
        >
          {isContainer ? (
            <ZIndexContext.Provider value={zIndex}>{innerProps.children}</ZIndexContext.Provider>
          ) : (
            innerProps.children
          )}
        </div>
      </Portal>
    );
  };

  /**
   * PreRenderInner — always mounted in the DOM, but manages z-index/scroll
   * reactively based on `open`. Portal is always rendered; visibility is
   * controlled via CSS display:none when closed.
   */
  const PreRenderInner: ParentComponent = innerProps => {
    let zIndex: number;
    const parentZIndex = useParentZIndex();

    if (p.customValue !== undefined) {
      zIndex = p.customValue;
    } else {
      const effectiveBase = computeEffectiveBase(p.type, baseIndex(), parentZIndex);
      const acquired = acquire(p.type, effectiveBase);
      zIndex = acquired.zIndex;
      onCleanup(function releaseZIndex() {
        release(acquired.registryKey, acquired.offset);
      });
    }

    // Reactively manage scroll lock based on open state.
    // Track whether we've acquired the lock to avoid double-release.
    let scrollLockHeld = false;
    createEffect(
      on(
        () => p.open,
        open => {
          if (open) {
            if (p.blockScroll && !scrollLockHeld) {
              acquireScrollLock();
              scrollLockHeld = true;
            }
            p.onZIndex?.(zIndex);
          } else {
            if (p.blockScroll && scrollLockHeld) {
              releaseScrollLock();
              scrollLockHeld = false;
            }
          }
        },
        { defer: false },
      ),
    );
    onCleanup(function releaseScrollLockIfHeld() {
      if (p.blockScroll && scrollLockHeld) {
        releaseScrollLock();
        scrollLockHeld = false;
      }
    });

    const isContainer = CONTAINER_TYPES.has(p.type as ZIndexType);

    return (
      <Portal>
        <div
          class={cn(p.positioning === 'fixed' ? 'fixed' : 'absolute', p.class)}
          style={{ 'z-index': zIndex, display: p.open ? undefined : 'none', ...p.position }}
        >
          {isContainer ? (
            <ZIndexContext.Provider value={zIndex}>{innerProps.children}</ZIndexContext.Provider>
          ) : (
            innerProps.children
          )}
        </div>
      </Portal>
    );
  };

  return p.preRender ? (
    <PreRenderInner>{p.children}</PreRenderInner>
  ) : (
    <Show when={p.open}>
      <Inner>{p.children}</Inner>
    </Show>
  );
};
